group[_ngcontent-%COMP%] {\n  margin-bottom: 20px;\n}\n\n.form-group[_ngcontent-%COMP%]   label[_ngcontent-%COMP%] {\n  display: block;\n  margin-bottom: 8px;\n  font-weight: bold;\n  color: #5e3614;\n}\n\n.form-group[_ngcontent-%COMP%]   input[_ngcontent-%COMP%], .form-group[_ngcontent-%COMP%]   select[_ngcontent-%COMP%] {\n  width: 100%;\n  padding: 12px;\n  border: 1px solid #d4c4a3;\n  border-radius: 4px;\n  font-size: 1rem;\n  background-color: #f9f3e0;\n}\n\n.form-group[_ngcontent-%COMP%]   select[_ngcontent-%COMP%] {\n  cursor: pointer;\n}\n\n\n\n.resumo[_ngcontent-%COMP%] {\n  display: flex;\n  flex-direction: column;\n  flex-wrap: wrap;\n  background-color: #e9dfc9;\n  border-radius: 8px;\n  padding: 20px;\n  box-shadow: 0 4px 8px rgba(0, 0, 0, 0.1);\n}\n\n.resumo[_ngcontent-%COMP%]   p[_ngcontent-%COMP%] {\n  margin-bottom: 10px;\n  font-size: 1.1rem;\n}\n\n.attribute-list[_ngcontent-%COMP%] {\n  list-style: none;\n  padding: 0;\n  margin: 10px 0 20px;\n}\n\n.attribute-list[_ngcontent-%COMP%]   li[_ngcontent-%COMP%] {\n  display: flex;\n  justify-content: space-between;\n  padding: 8px 10px;\n  margin-bottom: 5px;\n  background-color: #d4c4a3;\n  border-radius: 4px;\n}\n\n\n\n@media (max-width: 768px) {\n  .opcoes[_ngcontent-%COMP%] {\n    gap: 10px;\n  }\n\n  .opcao[_ngcontent-%COMP%] {\n    width: 120px;\n    padding: 10px;\n  }\n\n  .opcao[_ngcontent-%COMP%]   img[_ngcontent-%COMP%], .opcao-avatar[_ngcontent-%COMP%] {\n    width: 60px;\n    height: 60px;\n  }\n\n  h2[_ngcontent-%COMP%] {\n    font-size: 1.5rem;\n  }\n\n  .pagina[_ngcontent-%COMP%] {\n    padding: 20px;\n    min-height: auto;\n  }\n}\n/*# sourceMappingURL=data:application/json;charset=utf-8;base64, */"],
